  ('f382d156-0bfb-4705-b67e-a5be327c75b5', 'KIMCHI-2645', 'Wakame, dried seaweed 300g (3 x 100g) Nobi', 'Dried wakame seaweed, valued in Japanese cuisine for its mild taste and delicate texture. Efficient pack of 3 x 100g, ideal for various dishes.', 'Wakame, dried seaweed 300g (3 x 100g) Nobi', 'Dried wakame seaweed, valued in Japanese cuisine for its mild taste and delicate texture. Efficient pack of 3 x 100g, ideal for various dishes.'),
  ('701ba107-17bb-4021-afa2-74e4cf6f0280', 'KIMCHI-323', 'Wakame, dried seaweed 500g Nobi', 'Dried wakame seaweed, valued in Japanese cuisine for its mild taste and delicate texture. Economical 500g package, perfect for multiple uses.', 'Wakame, dried seaweed 500g Nobi', 'Dried wakame seaweed, valued in Japanese cuisine for its mild taste and delicate texture. Economical 500g package, perfect for multiple uses.'),
  ('326a7c2d-1f1c-411c-b05d-b29d3f3c5b68', 'KIMCHI-2726', 'Wakame, dried seaweed 50g - Asia Kitchen', 'Dried wakame seaweed, suitable for salads and soups. A versatile ingredient in Asian cuisine.', 'Wakame, dried seaweed 50g - Asia Kitchen', 'Dried wakame seaweed, suitable for salads and soups. A versatile ingredient in Asian cuisine.'),
  ('a105a088-e5ad-4ee6-b674-90ff5aaa97eb', 'KIMCHI-70', 'Wasabi powder 100g Asia Kitchen', 'Wasabi powder is a bold spice that can be mixed with water to create a paste with intense flavor and characteristic heat. Ideal for sushi and as a spicy accent in sauces.', 'Wasabi powder 100g Asia Kitchen', 'Wasabi powder is a bold spice that can be mixed with water to create a paste with intense flavor and characteristic heat. Ideal for sushi and as a spicy accent in sauces.'),
  ('c0db8c63-43cc-4dcb-a508-91c5ab7f76ac', 'KIMCHI-20', 'Wasabi powder 1kg Inaka', 'Spicy, aromatic paste made from Japanese horseradish – a classic addition to sushi and sashimi. Enhances the flavor of sauces, meats, and noodle dishes.', 'Wasabi powder 1kg Inaka', 'Spicy, aromatic paste made from Japanese horseradish – a classic addition to sushi and sashimi. Enhances the flavor of sauces, meats, and noodle dishes.')
), matched AS (
  SELECT
    p.salon_id,
    p.id AS template_id,
    s.slug,
    s.product_name,
    s.short_description,
    s.meta_title,
    s.meta_description
  FROM source s
  JOIN channels ch ON ch.slug = 'asiandeligo' AND ch.is_active = true
  JOIN products p ON p.id = s.template_id::uuid AND p.salon_id = ch.salon_id
  WHERE p.deleted_at IS NULL
), backup_insert AS (
  INSERT INTO asiandeligo_product_translations_backup_20260708
  SELECT pt.*
  FROM product_translations pt
  JOIN matched m ON m.template_id = pt.template_id AND m.salon_id = pt.salon_id
  WHERE pt.lang_id = 'en'
    AND NOT EXISTS (SELECT 1 FROM asiandeligo_product_translations_backup_20260708 b WHERE b.id = pt.id)
  RETURNING id
), upserted AS (
  INSERT INTO product_translations (
    id, salon_id, template_id, lang_id, product_name, short_description,
    meta_title, meta_description, created_at, updated_at
  )
  SELECT
    gen_random_uuid(),
    salon_id,
    template_id,
    'en',
    product_name,
    short_description,
    meta_title,
    meta_description,
    NOW(),
    NOW()
  FROM matched
  ON CONFLICT (template_id, lang_id) DO UPDATE SET
    product_name = EXCLUDED.product_name,
    short_description = EXCLUDED.short_description,
    meta_title = EXCLUDED.meta_title,
    meta_description = EXCLUDED.meta_description,
    updated_at = NOW()
  WHERE product_translations.salon_id = EXCLUDED.salon_id
  RETURNING template_id
)
SELECT
  (SELECT COUNT(*) FROM source) AS source_rows,
  (SELECT COUNT(*) FROM matched) AS matched_rows,
  (SELECT COUNT(*) FROM backup_insert) AS backed_up_rows,
  (SELECT COUNT(*) FROM upserted) AS upserted_rows;

-- Verify the printed counts after running. The backup table can be used to restore previous EN rows if needed.
COMMIT;
